  "Send feedback": { eng: "Send feedback", deu: "Feedback senden", esp: "Enviar comentarios", fra: "Envoyer un retour", ita: "Invia feedback", jpn: "フィードバックを送信", kor: "피드백 보내기", pol: "Wyślij opinię", ptb: "Enviar feedback", rus: "Отправить отзыв", spa: "Enviar comentarios", tha: "ส่งฟีดแบ็ก", tur: "Geri bildirim gönder", zhs: "发送反馈" },
